INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '002ba8c4-2a95-4e15-a8cc-d8c63cd04617',
  '00000000-0000-0000-0000-000000000001',
  $escape$Unity Scene Graph — Mastering Parent-Child Relationships$escape$,
  $escape$Unity's scene graph is a hierarchical structure of GameObjects, where each object has a parent-child relationship with others. The Transform component plays a crucial role in this structure, as it defines the position, rotation, and scale of an object in 3D space. When a GameObject is added as a child to another, its Transform is relative to its parent's Transform. This allows for complex animations and movements to be achieved by manipulating the parent's Transform, which in turn affects all its child objects. Understanding and utilizing this parent-child relationship is essential for efficient scene management and game development in Unity.$escape$,
  $escape$public class Example : MonoBehaviour { private void Start() { GameObject parent = new GameObject(); GameObject child = new GameObject(); child.transform.parent = parent.transform; } }$escape$,
  $escape$csharp$escape$,
