INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4a6a1d35-0788-4a9a-9b65-3a766fe8cbe8',
  '00000000-0000-0000-0000-000000000001',
  $escape$Unity Camera Systems: Follow Camera and Camera Shake$escape$,
  $escape$Unity's Camera class provides various properties to control the camera's behavior. To implement a follow camera, use the `Transform` component's `position` and `rotation` properties. For a camera shake effect, modify the `Camera.main.transform.localPosition` and `Camera.main.transform.localRotation` in a coroutine. When considering culling, use the `Camera.nearClipPlane` and `Camera.farClipPlane` properties to optimize rendering. Field of View (FOV) can be adjusted using the `Camera.fieldOfView` property. These properties can be accessed and modified in scripts attached to the Camera GameObject.$escape$,
  $escape$using UnityEngine;
public class CameraController : MonoBehaviour {
    public Transform target;
    public float smoothSpeed = 0.3F;
    private Vector3 offset;
    private void Start() {
        offset = transform.position - target.position;
    }
    private void LateUpdate() {
        Vector3 desiredPosition = target.position + offset;
        Vector3 smoothedPosition = Vector3.Lerp(transform.position, desiredPosition, smoothSpeed);
        transform.position = smoothedPosition;
    }
}$escape$,
  $escape$csharp$escape$,
