INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e5119960-f5a4-438d-8d8f-3849a567f591',
  '00000000-0000-0000-0000-000000000001',
  $escape$Unity Multiplayer Foundation: Client-Server vs P2P with MLAPI$escape$,
  $escape$When building multiplayer games in Unity, choosing between client-server and peer-to-peer (P2P) architectures is crucial. Unity's MLAPI (Multiplayer Low-Latency API) provides a foundation for both. Client-server is more scalable, while P2P reduces latency. For state synchronization, MLAPI uses a delta encoding approach. Rollback netcode can be implemented using MLAPI's built-in features like `NetworkVariable` and `NetworkBehaviour`. To get started, create a new MLAPI project and configure the `NetworkManager` component.$escape$,
  $escape$using Unity.Multiplayer.LowLatency; public class PlayerController : NetworkBehaviour { public NetworkVariable<int> health = new NetworkVariable<int>(100); }$escape$,
  $escape$csharp$escape$,
